sql_answer:
SELECT *
FROM Engineer_Visits
WHERE contact_staff_id IS NULL;

SELECT S.Sex, COUNT(*) AS student_count
FROM Student S
GROUP BY S.Sex;

SELECT
  100.0 * COUNT(CASE WHEN T1.gender_code = 'Female' THEN 1 END) / COUNT(T1.guest_id)
FROM Guests AS T1;

SELECT *
FROM Apartment_Buildings
WHERE building_address LIKE '%, AL%' OR building_address LIKE '%, CA%';

SELECT T1.apt_id
FROM Apartments AS T1
WHERE T1.bathroom_count = (SELECT bathroom_count FROM Apartments WHERE apt_id = 1) AND T1.apt_id != 1;

SELECT guest_id, gender_code, guest_first_name, guest_last_name, date_of_birth
FROM Guests
WHERE date_of_birth >= '1974-01-01' AND date_of_birth < '1979-01-01';

SELECT booking_status_code AS "Trạng thái đặt chỗ", COUNT(*) AS "Số lượt đặt"
FROM Apartment_Bookings
GROUP BY booking_status_code;

SELECT *
FROM Apartment_Bookings
WHERE CAST(strftime('%m', booking_start_date) AS INTEGER) BETWEEN 6 AND 8;

SELECT s.StuID, s.LName, s.Fname, s.Age
FROM Student s
WHERE s.Age BETWEEN 18 AND 20;

SELECT Major, COUNT(StuID) AS so_sinh_vien
FROM Student
GROUP BY Major;
